329	+/**
330	+ * Id-keyed list editing (ADR 0006, registration-launch Branch 2 sub-commit 2.2).
331	+ *
332	+ * The `/admin` editor used to grow/shrink lists by **array position** — it never
333	+ * could, in fact: the index-aligned `deepMerge` (`admin-form.ts`) can only
334	+ * overlay *existing* indices, so "add a speaker" / "remove a team member" was the
335	+ * CMS's headline gap (ADR 0006 Context). Now every list item carries a stable
336	+ * `id: ListItemId` (sub-commit 2.1), and structural edits address items **by
337	+ * id**, never by position.
338	+ *
339	+ * `applyListEdit` is the one deep operation: given the encoded document and a
340	+ * sequence of `ListOp`s, it navigates to each target list by its dotted path and
341	+ * applies an id-keyed add / remove / reorder. Identity — not position — is the
342	+ * key (`make-impossible-states-unrepresentable`): an id absent from a list is
343	+ * appended, an id present but not named survives, and a reorder is an explicit
344	+ * permutation of the surviving ids. The function is pure: it clones once and
345	+ * never mutates its input (`boundary-discipline`).
346	+ *
347	+ * The op-constructor sugar (`addOp`/`removeOp`/`reorderOp`), the control-field
348	+ * parser (`collectListOps`), and the id-keyed form field-name template
349	+ * (`fieldName`) are thin helpers around that one capability — they are NOT the
350	+ * interface's depth; `applyListEdit` is (`small-interface-deep-implementation`).
351	+ */
352	+
353	+import type { Json } from './admin-form';
354	+import type { ListItemId } from './schema';
355	+
356	+const isPlainObject = (value: Json): value is { readonly [k: string]: Json } =>
357	+  typeof value === 'object' && value !== null && !Array.isArray(value);
358	+
359	+/**
360	+ * A dotted path to a list (array) inside the encoded document — e.g. `team`, or
361	+ * `conferences.0.speakers`. Numeric segments index into an array (the document's
362	+ * `conferences`), string segments key into an object. The path addresses the
363	+ * **array**, not an item; the item is addressed by its `id` inside the `ListOp`.
364	+ */
365	+export type ListPath = string;
366	+
367	+/**
368	+ * A single structural list edit, addressed by item id (ADR 0006). Exactly one of
369	+ * add / remove / reorder per op so an op can never be two things at once
370	+ * (`make-impossible-states-unrepresentable`):
371	+ *   - `add`    — append a fresh item `{ id }` (empty otherwise) to the list. Its
372	+ *                required fields are absent, so it is publish-invalid until edited
373	+ *                (ADR 0006 consequence) — the id exists server-side so a later
374	+ *                photo upload / field edit has a target.
375	+ *   - `remove` — drop the item whose `id` matches; a no-op if absent.
376	+ *   - `reorder`— reorder the list to the given `ids` permutation; ids not present
377	+ *                are ignored and present-but-unnamed ids keep their relative order
378	+ *                after the named ones (so a partial order never drops an item).
379	+ */
380	+export type ListOp =
381	+  | { readonly add: { readonly listPath: ListPath; readonly id: ListItemId } }
382	+  | { readonly remove: { readonly listPath: ListPath; readonly id: ListItemId } }
383	+  | {
384	+      readonly reorder: {
385	+        readonly listPath: ListPath;
386	+        readonly ids: readonly ListItemId[];
387	+      };
388	+    };
389	+
390	+export const addOp = (listPath: ListPath, id: ListItemId): ListOp => ({
391	+  add: { listPath, id },
392	+});
393	+
394	+export const removeOp = (listPath: ListPath, id: ListItemId): ListOp => ({
395	+  remove: { listPath, id },
396	+});
397	+
398	+export const reorderOp = (
399	+  listPath: ListPath,
400	+  ids: readonly ListItemId[],
401	+): ListOp => ({ reorder: { listPath, ids } });
402	+
403	+/** The `id` of a list item, or `undefined` when the item is not an id-bearing object. */
404	+const itemId = (item: Json): string | undefined =>
405	+  isPlainObject(item) && typeof item['id'] === 'string' ? item['id'] : undefined;
406	+
407	+/**
408	+ * Apply one op to the array `list`, returning a fresh array (never mutating). The
409	+ * op kinds are exhaustive over the `ListOp` union, so adding a kind without
410	+ * handling it is a type error (`make-impossible-states-unrepresentable`).
411	+ */
412	+const applyOp = (list: readonly Json[], op: ListOp): readonly Json[] => {
413	+  if ('add' in op) {
414	+    // Appending a duplicate id would make two items share an identity, which the
415	+    // id-keyed merge could no longer distinguish — guard it (the caller mints a
416	+    // fresh id, so this only fires on a malformed resubmission).
417	+    if (list.some((item) => itemId(item) === op.add.id)) return list;
418	+    return [...list, { id: op.add.id }];
419	+  }
420	+  if ('remove' in op) {
421	+    return list.filter((item) => itemId(item) !== op.remove.id);
422	+  }
423	+  // reorder: place the named ids first in their given order, then append any
424	+  // surviving item the order omitted (in its original relative order) so a
425	+  // partial / stale order can never silently drop an item.
426	+  const named = new Map(
427	+    list.flatMap((item) => {
428	+      const id = itemId(item);
429	+      return id === undefined ? [] : ([[id, item]] as const);
430	+    }),
431	+  );
432	+  const ordered: Json[] = [];
433	+  const placed = new Set<string>();
434	+  for (const id of op.reorder.ids) {
435	+    const item = named.get(id);
436	+    if (item !== undefined && !placed.has(id)) {
437	+      ordered.push(item);
438	+      placed.add(id);
439	+    }
440	+  }
441	+  for (const item of list) {
442	+    const id = itemId(item);
443	+    if (id === undefined || !placed.has(id)) ordered.push(item);
444	+  }
445	+  return ordered;
446	+};
447	+
448	+/**
449	+ * Navigate to the array at `path` inside `root`, replace it via `update`, and
450	+ * return a fresh document. Intermediate containers are cloned along the path so
451	+ * the input is never mutated; a path that does not resolve to an array is left
452	+ * untouched (the caller's listPath always names a real list, but a malformed
453	+ * control field must not throw — the strict decode downstream is the gate).
454	+ */
455	+const updateListAtPath = (
456	+  root: Json,
457	+  path: readonly string[],
458	+  update: (list: readonly Json[]) => readonly Json[],
459	+): Json => {
460	+  const [head, ...rest] = path;
461	+  if (head === undefined) {
462	+    return Array.isArray(root) ? update(root) : root;
463	+  }
464	+  if (Array.isArray(root)) {
465	+    const index = Number(head);
466	+    if (!Number.isInteger(index) || index < 0 || index >= root.length) {
467	+      return root;
468	+    }
469	+    const next = [...root];
470	+    next[index] = updateListAtPath(root[index] as Json, rest, update);
471	+    return next;
472	+  }
473	+  if (isPlainObject(root)) {
474	+    if (!(head in root)) return root;
475	+    return { ...root, [head]: updateListAtPath(root[head] as Json, rest, update) };
476	+  }
477	+  return root;
478	+};
479	+
480	+/**
481	+ * Apply a sequence of id-keyed list ops to the encoded document, returning a new
482	+ * document (the input is never mutated — `boundary-discipline`). Ops apply in
483	+ * order, so a reorder naming a just-added id sees it. A `listPath` that does not
484	+ * resolve to an array is skipped; the merged result is Schema-decoded downstream,
485	+ * the single boundary where an invalid edit (an empty appended item on publish)
486	+ * is rejected.
487	+ */
488	+export const applyListEdit = (base: Json, ops: readonly ListOp[]): Json =>
489	+  ops.reduce((doc, op) => {
490	+    const listPath =
491	+      'add' in op
492	+        ? op.add.listPath
493	+        : 'remove' in op
494	+          ? op.remove.listPath
